function fibonacci(n: number): bigint {
  const normalized = Math.max(0, Math.trunc(n));
  if (normalized < 2) {
    return BigInt(normalized);
  }

  let previous = 0n;
  let current = 1n;
  for (let index = 2; index <= normalized; index += 1) {
    const next = previous + current;
    previous = current;
    current = next;
  }

  return current;
}

/**
 * Handles the gnosis app workflow.
 */
export function app(input: { n: number }): string {
  return fibonacci(input.n).toString();
}
